import"./main.min.js";import"./common.min.js";if(isMobile.any()){const o=document.querySelectorAll(".item-work");o.forEach(e=>{e.addEventListener("click",function(t){e.classList.contains("_hover")||(t.preventDefault(),o.forEach(r=>r.classList.remove("_hover")),e.classList.add("_hover"))})}),document.addEventListener("click",e=>{e.target.closest(".item-work")||o.forEach(t=>t.classList.remove("_hover"))})}
